def gen(rng, size):
    n = max(2, min(size, 300))
    nums = []
    for _ in range(n):
        if rng.random() < 0.35:
            nums.append(-1)
        else:
            nums.append(rng.randint(1, 200))
    if all(v == -1 for v in nums):
        nums[0] = rng.randint(1, 200)
    return [nums]

