class Solution:
    def minDifference(self, nums):
        vals = [v for v in nums if v != -1]
        limit = (max(vals) if vals else 1) + 12
        n = len(nums)
        best = None
        for x in range(1, limit + 1):
            for y in range(1, limit + 1):
                first = nums[0]
                cur = {x: 0, y: 0} if first == -1 else {first: 0}
                for i in range(1, n):
                    choices = [nums[i]] if nums[i] != -1 else [x, y]
                    nxt = {}
                    for lastv, md in cur.items():
                        for c in choices:
                            d = max(md, abs(lastv - c))
                            if c not in nxt or d < nxt[c]:
                                nxt[c] = d
                    cur = nxt
                if cur:
                    m = min(cur.values())
                    if best is None or m < best:
                        best = m
        return best

