class Solution:
    def minDifference(self, nums):
        n = len(nums)
        known_idx = [i for i, v in enumerate(nums) if v != -1]
        if not known_idx:
            return 0
        first_known = nums[known_idx[0]]
        last_known = nums[known_idx[-1]]
        positions = [-1] + known_idx + [n]
        values = [first_known] + [nums[i] for i in known_idx] + [last_known]
        runs = []
        for i in range(len(positions) - 1):
            gap = positions[i + 1] - positions[i] - 1
            runs.append((values[i], values[i + 1], gap))
        all_values = [nums[i] for i in known_idx]

        def feasible(d):
            for p, q, gap in runs:
                if gap == 0 and abs(p - q) > d:
                    return False
            gap_runs = [r for r in runs if r[2] > 0]
            if not gap_runs:
                return True
            x_val = min(all_values) + d
            need_y = []
            for p, q, length in gap_runs:
                if abs(p - x_val) <= d and abs(q - x_val) <= d:
                    continue
                cands = []
                lo_all = max(p, q) - d
                hi_all = min(p, q) + d
                if lo_all <= hi_all:
                    cands.append((max(lo_all, 1), hi_all))
                if length >= 2:
                    if abs(p - x_val) <= d:
                        lo = max(q - d, x_val - d)
                        hi = min(q + d, x_val + d)
                        if lo <= hi:
                            cands.append((max(lo, 1), hi))
                    if abs(q - x_val) <= d:
                        lo = max(p - d, x_val - d)
                        hi = min(p + d, x_val + d)
                        if lo <= hi:
                            cands.append((max(lo, 1), hi))
                if not cands:
                    return False
                need_y.append(cands)
            if not need_y:
                return True
            candidate_ys = set()
            for cands in need_y:
                for lo, hi in cands:
                    candidate_ys.add(lo)
                    candidate_ys.add(hi)
            for y in candidate_ys:
                if all(any(lo <= y <= hi for lo, hi in cands) for cands in need_y):
                    return True
            return False

        lo, hi = 0, 2 * 10 ** 9
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

