var minDifference = function(nums) {
    const n = nums.length;
    const knownIdx = [];
    for (let i = 0; i < n; i++) if (nums[i] !== -1) knownIdx.push(i);
    if (knownIdx.length === 0) return 0;
    const firstKnown = nums[knownIdx[0]];
    const lastKnown = nums[knownIdx[knownIdx.length - 1]];
    const positions = [-1, ...knownIdx, n];
    const values = [firstKnown, ...knownIdx.map(i => nums[i]), lastKnown];
    const runs = [];
    for (let i = 0; i < positions.length - 1; i++) {
        const gap = positions[i + 1] - positions[i] - 1;
        runs.push([values[i], values[i + 1], gap]);
    }
    const allValues = knownIdx.map(i => nums[i]);
    const minKnown = Math.min(...allValues);

    const feasible = (d) => {
        for (const [p, q, gap] of runs) {
            if (gap === 0 && Math.abs(p - q) > d) return false;
        }
        const gapRuns = runs.filter(r => r[2] > 0);
        if (gapRuns.length === 0) return true;
        const xVal = minKnown + d;
        const needY = [];
        for (const [p, q, length] of gapRuns) {
            if (Math.abs(p - xVal) <= d && Math.abs(q - xVal) <= d) continue;
            const cands = [];
            const loAll = Math.max(p, q) - d;
            const hiAll = Math.min(p, q) + d;
            if (loAll <= hiAll) cands.push([Math.max(loAll, 1), hiAll]);
            if (length >= 2) {
                if (Math.abs(p - xVal) <= d) {
                    const lo = Math.max(q - d, xVal - d);
                    const hi = Math.min(q + d, xVal + d);
                    if (lo <= hi) cands.push([Math.max(lo, 1), hi]);
                }
                if (Math.abs(q - xVal) <= d) {
                    const lo = Math.max(p - d, xVal - d);
                    const hi = Math.min(p + d, xVal + d);
                    if (lo <= hi) cands.push([Math.max(lo, 1), hi]);
                }
            }
            if (cands.length === 0) return false;
            needY.push(cands);
        }
        if (needY.length === 0) return true;
        const candidateYs = new Set();
        for (const cands of needY) {
            for (const [lo, hi] of cands) { candidateYs.add(lo); candidateYs.add(hi); }
        }
        for (const y of candidateYs) {
            if (needY.every(cands => cands.some(([lo, hi]) => lo <= y && y <= hi))) return true;
        }
        return false;
    };

    let lo = 0, hi = 2 * 1e9;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (feasible(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
